import{_ as a,o,c as i,a2 as l}from"./chunks/framework.Fbjs98zA.js";const m=JSON.parse('{"title":"Mango Fileproc Aspose License Resource","description":"","frontmatter":{},"headers":[],"relativePath":"mango/mango-infra/mango-infra-fileproc/mango-infra-fileproc-core/src/main/resources/aspose/README.md","filePath":"mango/mango-infra/mango-infra-fileproc/mango-infra-fileproc-core/src/main/resources/aspose/README.md"}'),s={name:"mango/mango-infra/mango-infra-fileproc/mango-infra-fileproc-core/src/main/resources/aspose/README.md"};function r(c,e,n,t,d,p){return o(),i("div",null,[...e[0]||(e[0]=[l('<h1 id="mango-fileproc-aspose-license-resource" tabindex="-1">Mango Fileproc Aspose License Resource <a class="header-anchor" href="#mango-fileproc-aspose-license-resource" aria-label="Permalink to &quot;Mango Fileproc Aspose License Resource&quot;">​</a></h1><h2 id="_1-概览" tabindex="-1">1. 概览 <a class="header-anchor" href="#_1-概览" aria-label="Permalink to &quot;1. 概览&quot;">​</a></h2><p>本目录保存 <code>mango-infra-fileproc</code> 默认 Aspose 授权资源，供文档转换、PDF 处理、图片转换等 fileproc 能力加载 Aspose license。</p><h2 id="_2-功能清单" tabindex="-1">2. 功能清单 <a class="header-anchor" href="#_2-功能清单" aria-label="Permalink to &quot;2. 功能清单&quot;">​</a></h2><table tabindex="0"><thead><tr><th>能力</th><th>常用入口</th></tr></thead><tbody><tr><td>使用 mango-infra-fileproc 内置 Aspose providers</td><td>Maven 依赖 / starter / Java API</td></tr><tr><td>需要从 classpath 默认加载 aspose/license.xml</td><td>Maven 依赖 / starter / Java API</td></tr><tr><td>需要说明外部 license 覆盖方式</td><td>Maven 依赖 / starter / Java API</td></tr></tbody></table><h2 id="_3-能力边界" tabindex="-1">3. 能力边界 <a class="header-anchor" href="#_3-能力边界" aria-label="Permalink to &quot;3. 能力边界&quot;">​</a></h2><ul><li>不提供文件处理 API 本身。</li><li>不负责 Aspose license 采购、续期或法律合规判断。</li><li>不替代 fileproc 模块总 README。</li></ul><h2 id="_4-模块入口" tabindex="-1">4. 模块入口 <a class="header-anchor" href="#_4-模块入口" aria-label="Permalink to &quot;4. 模块入口&quot;">​</a></h2><p>本 README 是资源级说明。实际转换能力位于 <code>mango-infra-fileproc-api</code>、<code>mango-infra-fileproc-core</code> 和 <code>mango-infra-fileproc-starter</code>。</p><h2 id="_5-接入方式" tabindex="-1">5. 接入方式 <a class="header-anchor" href="#_5-接入方式" aria-label="Permalink to &quot;5. 接入方式&quot;">​</a></h2><p>默认配置会从以下路径加载授权文件：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>classpath:/aspose/license.xml</span></span></code></pre></div><p>也可以通过配置项指定外部文件或目录。</p><h2 id="_6-配置说明" tabindex="-1">6. 配置说明 <a class="header-anchor" href="#_6-配置说明" aria-label="Permalink to &quot;6. 配置说明&quot;">​</a></h2><p>配置项：</p><ul><li><code>mango.fileproc.aspose.license-location</code></li><li><code>mango.fileproc.aspose.words-license-location</code></li><li><code>mango.fileproc.aspose.cells-license-location</code></li><li><code>mango.fileproc.aspose.slides-license-location</code></li><li><code>mango.fileproc.aspose.pdf-license-location</code></li><li><code>mango.fileproc.aspose.imaging-license-location</code></li></ul><p>相关测试还覆盖 <code>mango.fileproc.aspose.enabled</code> 和若干 <code>mango.fileproc.convert.*-enabled</code> 开关。</p><h2 id="_7-api-与扩展" tabindex="-1">7. API 与扩展 <a class="header-anchor" href="#_7-api-与扩展" aria-label="Permalink to &quot;7. API 与扩展&quot;">​</a></h2><ul><li><code>AsposeLicenseApi</code></li><li><code>DefaultAsposeLicenseApi</code></li><li><code>AsposeProduct</code></li><li>转换 provider 会按产品读取 license 内容，例如 PDF、IMAGING、WORDS、CELLS、SLIDES。</li></ul><h2 id="_8-数据与初始化" tabindex="-1">8. 数据与初始化 <a class="header-anchor" href="#_8-数据与初始化" aria-label="Permalink to &quot;8. 数据与初始化&quot;">​</a></h2><p>本目录不包含数据库 migration。<code>license.xml</code> 是 classpath 授权资源，生产使用前需要确认授权来源、有效期和合规范围。</p><h2 id="_9-管理入口" tabindex="-1">9. 管理入口 <a class="header-anchor" href="#_9-管理入口" aria-label="Permalink to &quot;9. 管理入口&quot;">​</a></h2><p>本资源不提供菜单、权限资源或租户数据。</p><h2 id="_10-快速开始" tabindex="-1">10. 快速开始 <a class="header-anchor" href="#_10-快速开始" aria-label="Permalink to &quot;10. 快速开始&quot;">​</a></h2><p>默认授权从 <code>classpath:/aspose/license.xml</code> 加载；需要替换时配置通用 <code>license-location</code>，如不同产品线使用不同授权，再配置 words、cells、slides、pdf、imaging 的专用 license location。专用配置优先用于对应产品线。</p><p>验收断言区分两层：Bean 装配成功只证明 provider 可用，真实转换/渲染样本且无水印才证明 Aspose 授权生效。禁用 <code>mango.fileproc.aspose.enabled=false</code> 后，依赖 Aspose 的 provider 不应被装配。</p><h2 id="_11-问题排查" tabindex="-1">11. 问题排查 <a class="header-anchor" href="#_11-问题排查" aria-label="Permalink to &quot;11. 问题排查&quot;">​</a></h2><ul><li>转换结果带水印时先检查 license 是否加载成功。</li><li>外部 license 路径应使用宿主应用可读取的文件或目录。</li><li>禁用 Aspose 后，依赖 Aspose 的转换 provider 不应被装配。</li></ul><h2 id="_12-相关文档" tabindex="-1">12. 相关文档 <a class="header-anchor" href="#_12-相关文档" aria-label="Permalink to &quot;12. 相关文档&quot;">​</a></h2><ul><li><a href="./../../../../../../../../mango-pmo/rules/backend/05-module">后端模块规范</a></li><li><a href="./../../../../../../../../mango-pmo/rules/08-capability-docs">能力说明维护规范</a></li></ul><h2 id="_13-补充资料" tabindex="-1">13. 补充资料 <a class="header-anchor" href="#_13-补充资料" aria-label="Permalink to &quot;13. 补充资料&quot;">​</a></h2><ul><li><a href="./../../../../../../../../mango-docs/capabilities/README">Mango 能力地图</a></li></ul>',32)])])}const f=a(s,[["render",r]]);export{m as __pageData,f as default};
